sys_script.script:
(function executeRule(current, previous) {
    var studentId = current.getValue('student');
    if (!studentId) {
        return;
    }

    var gr = new GlideRecord('x_1877508_metro_0_metro_student_pass');
    gr.addQuery('student', studentId);
    gr.addQuery('pass_status', 'IN', 'active,draft');
    gr.addQuery('sys_id', '!=', current.getUniqueValue());
    gr.query();

    if (gr.hasNext()) {
        gs.addErrorMessage('This student already has an active or pending student pass.');
        current.setAbortAction(true);
    }
})(current, previous);
